// src/pages/Checkout.js
import React, { useEffect, useState } from "react";
import "./Checkout.css";
import { Link, useNavigate } from "react-router-dom";
import axios from "axios";
import Footer from "./Footer";

function Checkout() {
  const navigate = useNavigate();
  const [cart, setCart] = useState([]);

  const [form, setForm] = useState({
    name: "",
    phone: "",
    email: "",
    address: "",
    city: "",
    pincode: "",
    paymentMethod: "COD",
  });

  const adminPhone = "916379112645"; // WhatsApp number with country code

  // ✅ Load Cart from LocalStorage
  useEffect(() => {
    const stored = JSON.parse(localStorage.getItem("cart") || "[]");
    setCart(stored);
  }, []);

  // ✅ Calculate Totals
  const total = cart.reduce((sum, it) => sum + it.price * it.quantity, 0);
  const delivery = total > 999 || total === 0 ? 0 : 49;
  const grandTotal = total + delivery;

  // ✅ Form Input Change
  const onChange = (e) => {
    const { name, value } = e.target;
    setForm((f) => ({ ...f, [name]: value }));
  };

  // ✅ Form Validation
  const validate = () => {
    if (!form.name.trim()) return "Enter your name";
    if (!/^\d{10}$/.test(form.phone)) return "Enter valid 10-digit phone";
    if (!/^\S+@\S+\.\S+$/.test(form.email)) return "Enter valid email";
    if (!form.address.trim()) return "Enter address";
    if (!form.city.trim()) return "Enter city";
    if (!/^[1-9][0-9]{5}$/.test(form.pincode)) return "Enter valid 6-digit pincode";
    if (cart.length === 0) return "Your cart is empty";
    return null;
  };

  // ✅ Save Order to Backend + WhatsApp
  const saveOrder = async (paymentStatus, razorpayId = null) => {
    const orderId = "ORD" + Date.now();

    const order = {
      orderId,
      customer: {
        name: form.name,
        phone: form.phone,
        email: form.email,
        address: `${form.address}, ${form.city} - ${form.pincode}`,
      },
      items: cart,
      totals: { total, delivery, grandTotal },
      paymentMethod: form.paymentMethod,
      paymentStatus,
      razorpayId,
      status: "Pending",
      createdAt: new Date().toISOString(),
    };

    // 1. Save order to backend
    await axios.post("http://localhost:5000/api/orders", order);

    // 2. Send WhatsApp to admin
    const msg = `🛍️ New Order Received!\n\nOrder ID: ${orderId}\nName: ${form.name}\nPhone: ${form.phone}\nEmail: ${form.email}\nTotal: ₹${grandTotal}\nAddress: ${form.address}, ${form.city} - ${form.pincode}`;
    const whatsappURL = `https://wa.me/${adminPhone}?text=${encodeURIComponent(msg)}`;
    window.open(whatsappURL, "_blank");

    // 3. Clear cart & redirect
    localStorage.removeItem("cart");
    navigate("/thank-you", { state: { orderId } });
  };

  // ✅ Place Order
  const placeOrder = async (e) => {
    e.preventDefault();
    const error = validate();
    if (error) {
      alert(error);
      return;
    }

    if (form.paymentMethod === "COD") {
      try {
        await saveOrder("Pending");
      } catch (err) {
        console.error("❌ COD Order Error:", err);
        alert("Order failed. Please try again.");
      }
    } else {
      try {
        // 1) Create order on backend
        const { data } = await axios.post("http://localhost:5000/api/payment/create-order", {
          amount: grandTotal,
        });

        if (!data?.success) {
          throw new Error(data?.message || "Order creation failed");
        }

        const { order, key } = data;

        // 2) Razorpay Checkout
        const options = {
          key,
          amount: order.amount,
          currency: order.currency,
          name: "CREWS Clothing",
          description: "Order Payment",
          order_id: order.id,
          handler: async function (response) {
            try {
              const verify = await axios.post("http://localhost:5000/api/payment/verify-payment", {
                razorpay_order_id: response.razorpay_order_id,
                razorpay_payment_id: response.razorpay_payment_id,
                razorpay_signature: response.razorpay_signature,
              });

              if (verify.data?.success) {
                await saveOrder("Paid", response.razorpay_payment_id);
              } else {
                alert("Payment verification failed");
              }
            } catch (vErr) {
              console.error("❌ Verification Error:", vErr);
              alert("Could not verify payment");
            }
          },
          prefill: {
            name: form.name,
            email: form.email,
            contact: form.phone,
          },
          notes: {
            address: `${form.address}, ${form.city} - ${form.pincode}`,
          },
          theme: { color: "#3399cc" },
        };

        const rzp = new window.Razorpay(options);
        rzp.on("payment.failed", function (resp) {
          console.error("Payment failed:", resp?.error);
          alert(resp?.error?.description || "Payment failed");
        });
        rzp.open();
      } catch (err) {
        console.error("❌ Razorpay Error:", err);
        alert(err?.message || "Payment failed. Try again.");
      }
    }
  };

  if (cart.length === 0) {
    return (
      <div className="checkout-empty">
        <h2>Your cart is empty 🛒</h2>
        <Link to="/products" className="btn-link">Continue Shopping</Link>
        <Footer />
      </div>
    );
  }

  return (
    <>
      <div className="checkout-container">
        <h2>Checkout</h2>
        <div className="checkout-grid">
          {/* Left — Form */}
          <form className="checkout-form" onSubmit={placeOrder}>
            <h3>Shipping Details</h3>

            <label>Full Name</label>
            <input name="name" value={form.name} onChange={onChange} placeholder="Suriya" />

            <div className="row-2">
              <div>
                <label>Phone</label>
                <input name="phone" value={form.phone} onChange={onChange} placeholder="9876543210" />
              </div>
              <div>
                <label>Email</label>
                <input name="email" value={form.email} onChange={onChange} placeholder="you@example.com" />
              </div>
            </div>

            <label>Address</label>
            <textarea name="address" value={form.address} onChange={onChange} placeholder="Door No, Street, Area" />

            <div className="row-2">
              <div>
                <label>City</label>
                <input name="city" value={form.city} onChange={onChange} placeholder="Chennai" />
              </div>
              <div>
                <label>Pincode</label>
                <input name="pincode" value={form.pincode} onChange={onChange} placeholder="600001" maxLength={6} />
              </div>
            </div>

            <label>Payment Method</label>
            <div className="payment-methods">
              <label>
                <input type="radio" name="paymentMethod" value="COD" checked={form.paymentMethod === "COD"} onChange={onChange} />
                Cash on Delivery
              </label>
              <label>
                <input type="radio" name="paymentMethod" value="ONLINE" checked={form.paymentMethod === "ONLINE"} onChange={onChange} />
                Online (UPI/Card)
              </label>
            </div>

            <button type="submit" className="place-order-btn">
              Place Order
            </button>
          </form>

          {/* Right — Summary */}
          <div className="checkout-summary">
            <h3>Order Summary</h3>
            <div className="items">
              {cart.map((it) => (
                <div className="item" key={it._id + it.selectedSize}>
                  <img src={(it.images && it.images[0]) || it.image} alt={it.name} />
                  <div>
                    <p className="name">{it.name}</p>
                    <p className="muted">Size: {it.selectedSize}</p>
                    <p className="muted">Qty: {it.quantity}</p>
                  </div>
                  <div className="price">₹{it.price * it.quantity}</div>
                </div>
              ))}
            </div>

            <div className="totals">
              <div><span>Subtotal</span><span>₹{total}</span></div>
              <div><span>Delivery</span><span>{delivery === 0 ? "FREE" : `₹${delivery}`}</span></div>
              <div className="grand"><span>Total</span><span>₹{grandTotal}</span></div>
            </div>
          </div>
        </div>
      </div>
      <Footer />
    </>
  );
}

export default Checkout;
